import {KitsMultiSelect} from "../../../../form/selects";
import type {FilterEl} from "../Filter";

const MultiSelectFilter: FilterEl<{
    list:
        | {
        label: string;
        value: any;
    }[]
        | undefined;
    filter?: boolean;
}> = ({ list, filter = true, ...options }) => {
    const listArray = Array.isArray(list) ? list : [];

    return (
        <KitsMultiSelect
            attached
            id={"filter-multiple"}
            withFilter={filter}
            value={options.value ?? undefined}
            list={listArray}
            filterBy={"label"}
            onChange={(e: any) => options.filterApplyCallback(e.value)}
            inputSize="sm"
        />
    );
};

export default MultiSelectFilter;
